// Parse routing configuration and determine destinations
const document = $input.first().json;
const routingConfigItems = $input.all().slice(1).map(item => item.json);

// Initialize routing rules with defaults
let routingRules = {
  destinations: [],
  categoryMappings: {},
  minValidationScore: 70,
  autoRoute: false
};

// Parse config values
routingConfigItems.forEach(config => {
  const key = config.config_key;
  const value = config.config_value;

  if (key === 'routing_destinations') {
    routingRules.destinations = value || [];
  } else if (key === 'category_mappings') {
    routingRules.categoryMappings = value || {};
  } else if (key === 'routing_min_validation_score') {
    routingRules.minValidationScore = value || 70;
  } else if (key === 'routing_auto') {
    routingRules.autoRoute = value || false;
  }
});

// Determine destinations for this document
const category = document.category || 'other';
const validationScore = document.validation_score || 0;

let destinations = [];

// Check category-specific mappings first
if (routingRules.categoryMappings[category]) {
  destinations = routingRules.categoryMappings[category];
}

// If no category mapping, use default destinations
if (destinations.length === 0) {
  destinations = routingRules.destinations;
}

// Determine if document should be routed
const shouldRoute = validationScore >= routingRules.minValidationScore && 
                     routingRules.autoRoute && 
                     destinations.length > 0;

// Prepare routing data
const routingData = {
  document_id: document.document_id,
  document_uuid: document.document_uuid,
  client_id: document.client_id,
  original_filename: document.original_filename,
  storage_path: document.storage_path,
  category: category,
  priority: document.priority,
  validation_score: validationScore,
  extracted_data: document.result_data || {},
  confidence_score: document.confidence_score || 0,
  routing_rules: routingRules,
  destinations: destinations,
  should_route: shouldRoute,
  timestamp: new Date().toISOString()
};

return [{ json: routingData }];

// Route document to specific destination
const data = $input.first().json;
const document = data;
const destination = document.destinations[data.$index || 0];

const destinationType = destination.type;
const destinationConfig = destination.config || {};

let result = {
  document_id: document.document_id,
  destination_type: destinationType,
  destination_config: destinationConfig,
  status: 'pending',
  message: '',
  sent_at: null
};

try {
  switch(destinationType) {
    case 'webhook':
      // Prepare webhook payload
      const webhookPayload = {
        document_id: document.document_uuid,
        document_uuid: document.document_uuid,
        client_id: document.client_id,
        filename: document.original_filename,
        category: document.category,
        priority: document.priority,
        validation_score: document.validation_score,
        extracted_data: document.extracted_data,
        storage_path: document.storage_path,
        timestamp: document.timestamp
      };

      // In production, this would be an actual HTTP POST
      result.message = `Webhook call would be made to: ${destinationConfig.url}`;
      result.payload = webhookPayload;
      result.status = 'sent';
      result.sent_at = new Date().toISOString();
      break;

    case 'email':
      result.message = `Email would be sent to: ${destinationConfig.recipient || destinationConfig.to}`;
      result.recipient = destinationConfig.recipient;
      result.subject = `New ${document.category} document: ${document.original_filename}`;
      result.status = 'sent';
      result.sent_at = new Date().toISOString();
      break;

    case 'slack':
      result.message = `Slack message would be sent to: ${destinationConfig.channel}`;
      result.channel = destinationConfig.channel;
      result.status = 'sent';
      result.sent_at = new Date().toISOString();
      break;

    case 'storage':
      result.message = `Document would be copied to storage: ${destinationConfig.path}`;
      result.storage_path = destinationConfig.path;
      result.status = 'sent';
      result.sent_at = new Date().toISOString();
      break;

    case 'database':
      result.message = `Document data would be inserted into table: ${destinationConfig.table}`;
      result.table = destinationConfig.table;
      result.status = 'sent';
      result.sent_at = new Date().toISOString();
      break;

    default:
      result.status = 'failed';
      result.message = `Unknown destination type: ${destinationType}`;
  }

} catch (error) {
  result.status = 'failed';
  result.message = error.message;
}

return [{ json: result }];
